+                let _ = reply.send(self.sum);
+                Box::pin(async {})
+            }
+
+            fn handle_cast(
+                &mut self,
+                _cx: &Cx,
+                msg: AccumCast,
+            ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
+                match msg {
+                    AccumCast::Add(n) => self.sum += n,
+                }
+                Box::pin(async {})
+            }
+
+            fn on_stop(&mut self, _cx: &Cx) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
+                self.final_sum.store(self.sum, Ordering::SeqCst);
+                Box::pin(async {})
